// ==========================================
// 1. 全地形参数提取器：去各个可能的角落找数据
// ==========================================
let params = {};

if (typeof query === 'string') {
  // 场景 A：你在 n8n 界面手动点击 Test，Query 框里的内容是一个字符串
  try {
    params = JSON.parse(query); 
  } catch (e) {
    return "测试参数格式错误：请确保 Query 框里填入的是合法的 JSON。";
  }
} else if (typeof query === 'object' && query !== null) {
  // 场景 B：某些 n8n 版本中，Agent 真实运行会把对象放在 query 里
  params = query;
} else if (typeof $json !== 'undefined' && $json !== null) {
  // 场景 C：标准的 n8n 节点数据流
  params = $json;
} else if (typeof $input !== 'undefined' && $input.item && $input.item.json) {
  // 场景 D：深层嵌套对象
  params = $input.item.json;
}

// ==========================================
// 2. 提取、类型转换与容错处理
// ==========================================
const x = parseFloat(params.x);
const y = parseFloat(params.y);
const floor = typeof params.floor !== 'undefined' && params.floor !== null ? parseInt(params.floor) : 0;
const goal_yaw_deg = typeof params.goal_yaw_deg !== 'undefined' && params.goal_yaw_deg !== null ? parseFloat(params.goal_yaw_deg) : null;

// 防御性校验
if (isNaN(x) || isNaN(y)) {
  // 故意抛出 params 的内容，方便调试看 n8n 到底传了什么
  return `[参数校验失败] 必须提供数字 x 和 y 坐标。系统实际提取到的参数字典为: ${JSON.stringify(params)}。`;
}

// 组装最终请求体
const requestBody = { x: x, y: y, floor: floor };
if (goal_yaw_deg !== null && !isNaN(goal_yaw_deg)) {
  requestBody.goal_yaw_deg = goal_yaw_deg;
}

// ==========================================
// 3. 执行真正的物理导航调度请求
// ==========================================
try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://127.0.0.1:5001/api/robot/navigate',
    body: requestBody,
    json: true 
  });

  return JSON.stringify(response);

} catch (error) {
  const serverError = error.response ? JSON.stringify(error.response.data) : error.message;
  return `目标服务器拒绝了请求 (400)。\n发送的数据: ${JSON.stringify(requestBody)}\n服务器返回的错误: ${serverError}`;
}

// ==========================================
// 查询类 API 不需要参数提取器，直接发起请求
// ==========================================
try {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://127.0.0.1:5001/api/objects',
    json: true // 自动解析返回的 JSON 数据
  });

  return JSON.stringify(response);

} catch (error) {
  // 优雅捕获并返回报错信息给大模型
  const serverError = error.response ? JSON.stringify(error.response.data) : error.message;
  return `查询失败。\n服务器返回的错误: ${serverError}`;
}

// ==========================================
// 1. 全地形参数提取器：去各个可能的角落找数据
// ==========================================
let params = {};

if (typeof query === 'string') {
  try {
    params = JSON.parse(query); 
  } catch (e) {
    return "测试参数格式错误：请确保 Query 框里填入的是合法的 JSON。";
  }
} else if (typeof query === 'object' && query !== null) {
  params = query;
} else if (typeof $json !== 'undefined' && $json !== null) {
  params = $json;
} else if (typeof $input !== 'undefined' && $input.item && $input.item.json) {
  params = $input.item.json;
}

// ==========================================
// 2. 提取、类型转换与容错处理
// ==========================================
const object_name = params.object_name;
const target_name = params.target_name;

// 防御性校验：确保大模型确实提取到了这两个必填名字
if (!object_name || !target_name) {
  return `[参数校验失败] 必须提供 object_name 和 target_name。系统实际提取到的参数字典为: ${JSON.stringify(params)}。`;
}

// 组装最终请求体
const requestBody = { 
  object_name: object_name, 
  target_name: target_name 
};

// ==========================================
// 3. 发送 Pick&Place 请求
// ==========================================
try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://127.0.0.1:5001/api/robot/pick_place',
    body: requestBody,
    json: true 
  });

  return JSON.stringify(response);

} catch (error) {
  const serverError = error.response ? JSON.stringify(error.response.data) : error.message;
  return `Pick&Place 请求被拒绝。\n发送的数据: ${JSON.stringify(requestBody)}\n服务器返回的错误: ${serverError}`;
}
